import { useState, useEffect } from "react";
import axios from "axios";
const API = "http://localhost:8001";
export default function App() {
  const [url, setUrl] = useState("");
  const [message, setMessage] = useState("");
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);
  const [recentScans, setRecentScans] = useState([]);
  const [stats] = useState({ total: 1247, blocked: 983, indians: 298450 });
  useEffect(() => { fetchRecent(); }, []);
  const fetchRecent = async () => {
    try {
      const res = await axios.get(`${API}/recent-scans`);
      setRecentScans(res.data.scans || []);
    } catch (e) {}
  };
  const scan = async () => {
    if (!url) return;
    setLoading(true);
    setResult(null);
    try {
      const res = await axios.post(`${API}/scan`, { url, message });
      setResult(res.data);
      fetchRecent();
    } catch (e) { alert("Backend not running!"); }
    setLoading(false);
  };
  const getColor = (score) => {
    if (score >= 75) return "#ff2d2d";
    if (score >= 50) return "#ff8800";
    if (score >= 30) return "#ffcc00";
    return "#00c853";
  };
  const signals = result?.signals ? [
    { name: "AI Analysis", score: result.signals.ai_analysis?.ai_score || 0, max: 100, icon: "🧠", desc: result.signals.ai_analysis?.explanation || "" },
    { name: "Ghost Sandbox", score: result.signals.sandbox?.score || 0, max: 25, icon: "👻", desc: result.signals.sandbox?.verdict || "" },
    { name: "Click Velocity", score: result.signals.click_velocity?.score || 0, max: 20, icon: "⚡", desc: result.signals.click_velocity?.verdict || "" },
    { name: "Geo Velocity", score: result.signals.geo_velocity?.score || 0, max: 15, icon: "🌍", desc: result.signals.geo_velocity?.verdict || "" },
    { name: "Dwell Time", score: result.signals.dwell_time?.score || 0, max: 10, icon: "⏱️", desc: result.signals.dwell_time?.verdict || "" },
    { name: "VirusTotal", score: Math.min((result.signals.virustotal?.malicious_engines || 0) * 15, 40), max: 40, icon: "🔬", desc: `${result.signals.virustotal?.malicious_engines || 0} malicious engines out of ${result.signals.virustotal?.total_engines || 0} — ${result.signals.virustotal?.verdict || "UNKNOWN"}` },
  ] : [];
  return (
    <div style={{ background: "#0a0a0a", minHeight: "100vh", color: "white", fontFamily: "monospace" }}>
      {/* STATS BAR */}
      <div style={{ display: "flex", justifyContent: "space-around", background: "#111", padding: "16px", borderBottom: "2px solid #222" }}>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "1.8rem", color: "#ff2d2d", fontWeight: "bold" }}>{stats.total.toLocaleString()}</div>
          <div style={{ color: "#888", fontSize: "0.7rem" }}>URLS SCANNED</div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "1.8rem", color: "#ff8800", fontWeight: "bold" }}>{stats.blocked.toLocaleString()}</div>
          <div style={{ color: "#888", fontSize: "0.7rem" }}>THREATS BLOCKED</div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "1.8rem", color: "#00c853", fontWeight: "bold" }}>{stats.indians.toLocaleString()}</div>
          <div style={{ color: "#888", fontSize: "0.7rem" }}>INDIANS PROTECTED</div>
        </div>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontSize: "1.8rem", color: "#00bcd4", fontWeight: "bold" }}>95</div>
          <div style={{ color: "#888", fontSize: "0.7rem" }}>ENGINES ACTIVE</div>
        </div>
      </div>
      {/* HEADER */}
      <div style={{ textAlign: "center", padding: "30px" }}>
        <h1 style={{ color: "#ff2d2d", fontSize: "2.5rem", margin: 0 }}>🛡️ ShieldNetX</h1>
        <p style={{ color: "#888" }}>AI-Powered Phishing Intelligence Platform</p>
      </div>
      {/* SCAN BOX */}
      <div style={{ maxWidth: "700px", margin: "0 auto", padding: "0 20px" }}>
        <input value={url} onChange={e => setUrl(e.target.value)} placeholder="Enter URL to scan..." style={{ width: "100%", padding: "12px", background: "#111", border: "1px solid #333", color: "white", borderRadius: "6px", fontSize: "1rem", marginBottom: "10px", boxSizing: "border-box" }} />
        <input value={message} onChange={e => setMessage(e.target.value)} placeholder="SMS/message context (optional)..." style={{ width: "100%", padding: "12px", background: "#111", border: "1px solid #333", color: "white", borderRadius: "6px", fontSize: "1rem", marginBottom: "10px", boxSizing: "border-box" }} />
        <button onClick={scan} disabled={loading} style={{ width: "100%", padding: "14px", background: loading ? "#333" : "#ff2d2d", color: "white", border: "none", borderRadius: "6px", fontSize: "1.1rem", cursor: "pointer", fontWeight: "bold" }}>
          {loading ? "⏳ SCANNING..." : "🔍 SCAN NOW"}
        </button>
      </div>
      {/* RESULT */}
      {result && (
        <div style={{ maxWidth: "700px", margin: "30px auto", padding: "0 20px" }}>
          <div style={{ background: "#111", border: `2px solid ${getColor(result.threat_score)}`, borderRadius: "10px", padding: "24px", textAlign: "center" }}>
            <div style={{ fontSize: "4rem", fontWeight: "bold", color: getColor(result.threat_score) }}>{result.threat_score}</div>
            <div style={{ color: "#888" }}>THREAT SCORE OUT OF 100</div>
            <div style={{ fontSize: "1.5rem", color: getColor(result.threat_score), marginTop: "8px" }}>{result.threat_level}</div>
          </div>
          <div style={{ marginTop: "20px" }}>
            {signals.map((sig, i) => (
              <div key={i} style={{ background: "#111", borderRadius: "8px", padding: "14px", marginBottom: "10px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "6px" }}>
                  <span>{sig.icon} {sig.name}</span>
                  <span style={{ color: getColor((sig.score / sig.max) * 100) }}>{sig.score}/{sig.max}</span>
                </div>
                <div style={{ background: "#222", borderRadius: "4px", height: "8px" }}>
                  <div style={{ width: `${Math.min((sig.score / sig.max) * 100, 100)}%`, background: getColor((sig.score / sig.max) * 100), height: "8px", borderRadius: "4px" }} />
                </div>
                <div style={{ color: "#666", fontSize: "0.75rem", marginTop: "4px" }}>{sig.desc}</div>
              </div>
            ))}
          </div>
        </div>
      )}
      {/* RECENT SCANS */}
      {recentScans.length > 0 && (
        <div style={{ maxWidth: "700px", margin: "20px auto", padding: "0 20px 40px" }}>
          <h3 style={{ color: "#888" }}>Recent Scans</h3>
          {recentScans.slice(0, 5).map((scan, i) => (
            <div key={i} style={{ display: "flex", justifyContent: "space-between", background: "#111", padding: "10px 14px", borderRadius: "6px", marginBottom: "6px" }}>
              <span style={{ color: "#aaa", fontSize: "0.85rem" }}>{scan.url?.substring(0, 50)}...</span>
              <span style={{ color: getColor(scan.threat_score), fontWeight: "bold" }}>{scan.threat_score}/100</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
